type Part_linkFormCallback struct {
	part_link *models.Part_link

	// If the form call is called on the creation of a new instnace
	CreationMode bool

	probe *Probe

	formGroup *form.FormGroup
}

func (part_linkFormCallback *Part_linkFormCallback) OnSave() {
	part_linkFormCallback.probe.stageOfInterest.Lock()
	defer part_linkFormCallback.probe.stageOfInterest.Unlock()

	// log.Println("Part_linkFormCallback, OnSave")

	// checkout formStage to have the form group on the stage synchronized with the
	// back repo (and front repo)
	part_linkFormCallback.probe.formStage.Checkout()

	if part_linkFormCallback.part_link == nil {
		part_linkFormCallback.part_link = new(models.Part_link).Stage(part_linkFormCallback.probe.stageOfInterest)
	}
	part_link_ := part_linkFormCallback.part_link
	_ = part_link_

	for _, formDiv := range part_linkFormCallback.formGroup.FormDivs {
		switch formDiv.Name {
		// insertion point per field
		case "Name":
			FormDivBasicFieldToField(&(part_link_.Name), formDiv)
		case "Href":
			FormDivBasicFieldToField(&(part_link_.Href), formDiv)
		case "Type":
			FormDivBasicFieldToField(&(part_link_.Type), formDiv)
		case "Role":
			FormDivBasicFieldToField(&(part_link_.Role), formDiv)
		case "Title":
			FormDivBasicFieldToField(&(part_link_.Title), formDiv)
		case "Show":
			FormDivBasicFieldToField(&(part_link_.Show), formDiv)
		case "Actuate":
			FormDivBasicFieldToField(&(part_link_.Actuate), formDiv)
		case "Instrument_link":
			instanceSet := *models.GetGongstructInstancesSetFromPointerType[*models.Instrument_link](part_linkFormCallback.probe.stageOfInterest)
			instanceSlice := make([]*models.Instrument_link, 0)

			// make a map of all instances by their ID
			map_id_instances := make(map[uint]*models.Instrument_link)

			for instance := range instanceSet {
				id := models.GetOrderPointerGongstruct(
					part_linkFormCallback.probe.stageOfInterest,
					instance,
				)
				map_id_instances[id] = instance
			}

			rowIDs, err := DecodeStringToIntSlice(formDiv.FormEditAssocButton.AssociationStorage)

			if err != nil {
				log.Panic("not a good storage", formDiv.FormEditAssocButton.AssociationStorage)
			}
			map_RowID_ID := GetMap_RowID_ID[*models.Instrument_link](part_linkFormCallback.probe.stageOfInterest)

			for _, rowID := range rowIDs {
				if id, ok := map_RowID_ID[int(rowID)]; ok {
					instanceSlice = append(instanceSlice, map_id_instances[id])
				} else {
					log.Panic("not a good storage", formDiv.FormEditAssocButton.AssociationStorage, "unkown row id", rowID)
				}
			}
			part_link_.Instrument_link = instanceSlice
			part_linkFormCallback.probe.UpdateSliceOfPointersCallback(part_link_, "Instrument_link", &part_link_.Instrument_link)

		case "Group_link":
			FormDivBasicFieldToField(&(part_link_.Group_link), formDiv)
		case "Score_part:Part_link":
			// 1. Decode the AssociationStorage which contains the rowIDs of the Score_part instances
			rowIDs, err := DecodeStringToIntSlice(formDiv.FormEditAssocButton.AssociationStorage)
			if err != nil {
				log.Panic("not a good storage", formDiv.FormEditAssocButton.AssociationStorage)
			}

			// 2. Build a map of target Score_part instances by their ID
			map_RowID_ID := GetMap_RowID_ID[*models.Score_part](part_linkFormCallback.probe.stageOfInterest)
			targetScore_partIDs := make(map[uint]bool)
			for _, rowID := range rowIDs {
				if id, ok := map_RowID_ID[int(rowID)]; ok {
					targetScore_partIDs[id] = true
				} else {
					log.Panic("not a good storage", formDiv.FormEditAssocButton.AssociationStorage, "unknown row id", rowID)
				}
			}

			// 3. Iterate over all Score_part instances and update their Part_link slice
			for _score_part := range *models.GetGongstructInstancesSetFromPointerType[*models.Score_part](part_linkFormCallback.probe.stageOfInterest) {
				id := models.GetOrderPointerGongstruct(part_linkFormCallback.probe.stageOfInterest, _score_part)

				// if Score_part is selected
				if targetScore_partIDs[id] {
					// ensure part_link_ is in _score_part.Part_link
					found := false
					for _, _b := range _score_part.Part_link {
						if _b == part_link_ {
							found = true
							break
						}
					}
					if !found {
						_score_part.Part_link = append(_score_part.Part_link, part_link_)
						part_linkFormCallback.probe.UpdateSliceOfPointersCallback(_score_part, "Part_link", &_score_part.Part_link)
					}
				} else {
					// ensure part_link_ is NOT in _score_part.Part_link
					idx := slices.Index(_score_part.Part_link, part_link_)
					if idx != -1 {
						_score_part.Part_link = slices.Delete(_score_part.Part_link, idx, idx+1)
						part_linkFormCallback.probe.UpdateSliceOfPointersCallback(_score_part, "Part_link", &_score_part.Part_link)
					}
				}
			}
		}
	}

	// manage the suppress operation
	if part_linkFormCallback.formGroup.HasSuppressButtonBeenPressed {
		part_link_.Unstage(part_linkFormCallback.probe.stageOfInterest)
	}

	part_linkFormCallback.probe.stageOfInterest.Commit()
	updateProbeTable[*models.Part_link](
		part_linkFormCallback.probe,
	)

	// display a new form by reset the form stage
	if part_linkFormCallback.CreationMode || part_linkFormCallback.formGroup.HasSuppressButtonBeenPressed {
		part_linkFormCallback.probe.formStage.Reset()
		newFormGroup := (&form.FormGroup{
			Name: FormName,
		}).Stage(part_linkFormCallback.probe.formStage)
		newFormGroup.OnSave = __gong__New__Part_linkFormCallback(
			nil,
			part_linkFormCallback.probe,
			newFormGroup,
		)
		part_link := new(models.Part_link)
		FillUpForm(part_link, newFormGroup, part_linkFormCallback.probe)
		part_linkFormCallback.probe.formStage.Commit()
	}

	part_linkFormCallback.probe.ux_tree()
}
